// Filter patients whose follow-up is today and have not been messaged recently.
const items = $input.all();
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const maxMessages = parseInt($env.MAX_MESSAGE_COUNT) || 5;
const minHours = parseInt($env.MIN_HOURS_BETWEEN_MESSAGES) || 23;
const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: tz });
const filtered = items.filter(item => {
  const p = item.json;
  const fuDate = p.follow_up_date ? new Date(p.follow_up_date).toLocaleDateString('en-CA', { timeZone: tz }) : null;
  if (!fuDate || fuDate !== todayStr) return false;
  if (p.status && p.status !== 'pending') return false;
  if ((parseInt(p.message_count) || 0) >= maxMessages) return false;
  if (!p.phone || !/^\+[1-9]\d{6,14}$/.test(p.phone)) return false;
  if (p.last_message_sent) {
    const hoursSince = (now - new Date(p.last_message_sent)) / (1000 * 60 * 60);
    if (hoursSince < minHours) return false;
  }
  return true;
});
if (filtered.length === 0) return [{ json: { _skip: true, reason: 'No same-day appointments today', todayStr } }];
return filtered.map(item => {
  const p = item.json;
  const name = p.name || 'there';
  const doctor = p.doctor_name || $env.DEFAULT_DOCTOR_NAME || 'your doctor';
  const clinic = p.clinic_name || $env.DEFAULT_CLINIC_NAME || 'our clinic';
  return { json: { ...p, _clinic_id: p.clinic_id, _workflow: 'workflow-2-sameday-reminder', _message_type: 'same_day_reminder', _scheduled_date: todayStr, _to_phone: 'whatsapp:' + p.phone, _name: name, _doctor_name: doctor, _clinic_name: clinic, _content_sid: $env.TWILIO_CONTENT_PATIENT_REMINDER || $env.TWILIO_CONTENT_SAME_DAY_REMINDER || '', _content_variables: JSON.stringify({ '1': name, '2': doctor, '3': clinic }), _message_body: `Good morning ${name}! Just a friendly reminder - your visit with ${doctor} at ${clinic} is today. We are ready for you whenever you arrive. See you soon, take care on your way!` } };
});
